const Q_BIOLOGY_1992=[{"id": "objective>Biology>1992>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle involved in tissue respiration is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">endoplasmic reticulum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ribosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">golgi body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mitochondrion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle involved in tissue respiration is the mitochondrion. Mitochondria are known as the powerhouses of the cell because they produce ATP through the process of cellular respiration, which is essential for energy production in tissues.</div>", "topic": "CELL STRUCTURE AND FUNCTIONS"}, {"id": "objective>Biology>1992>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tissue can best be defined as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an aggregate of similar cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an aggregate of cells performing a similar function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an aggregate of similar cells performing the same function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a mixture of different cells types performing the same function</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tissue can best be defined as an aggregate of similar cells performing the same function. This definition captures the essence of what a tissue is, as it emphasizes both the similarity of the cells and their collective role in a specific function.</div>", "topic": "CELL STRUCTURE AND FUNCTIONS"}, {"id": "objective>Biology>1992>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following correctly summarizes the life cycle of fern plant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Spore → prothallus → thallus → sporangium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Male and female gamentangia → zygospores → sporangium → spores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spore → thallus → spermatozoa + ovum → sporangium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prothallus → spermatozoid + egg cell → leafy plant → sporangium → spore</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The life cycle of a fern plant is summarized as prothallus → spermatozoid + egg cell → leafy plant → sporangium → spore. This sequence reflects the alternation of generations in ferns, where the prothallus is the gametophyte stage, and the leafy plant is the sporophyte stage.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>1992>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major difference between platyhelminthees and coelenterates is that platyhelminthes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are multicellular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have developed a mesoderm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduce sexually</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduce asexually</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major difference between platyhelminthes and coelenterates is that platyhelminthes have developed a mesoderm. This mesoderm allows for more complex body structures and systems, distinguishing them from coelenterates, which are typically diploblastic and lack a true mesoderm.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>1992>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The essential structural difference between hydra and tapeworm is that while Hydra</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">has tentacles, tapeworm is parasitic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is diploblastic, tapeworm is triplobastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a mouth, tapeworm feeds by suckers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has mesoderm, tapeworm has mesogloea</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The essential structural difference between hydra and tapeworm is that while Hydra has a mouth, tapeworm feeds by suckers. This highlights the different feeding mechanisms of these organisms, with Hydra being a free-living organism that captures prey, while tapeworms are parasitic and absorb nutrients directly from their host.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTIONS IN ORGANISMS"}, {"id": "objective>Biology>1992>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The flowering period of plants in a habitat is determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">duration of sunlight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensity and duration of rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative humidity of the atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature of the habitat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The flowering period of plants is primarily influenced by the duration of sunlight, which is a key factor in the process of photoperiodism. Photoperiodism is the physiological reaction of organisms to the length of day or night. Plants use the duration of sunlight to determine the appropriate time for flowering.</div>", "topic": "HABITAT"}, {"id": "objective>Biology>1992>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled X is used by the organism in the same way as man uses his?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oesophagus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intestine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled X is likely the trachea, which is used for respiration in many organisms, similar to how humans use their trachea to transport air to the lungs. The trachea is a tube that connects the throat to the lungs, allowing for the passage of air.</div>", "topic": "CELL STRUCTURE AND FUNCTIONS"}, {"id": "objective>Biology>1992>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure labelled Y is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleolous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">macronucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contractile vacuole</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled Y is the contractile vacuole, which is an organelle found in some protists and unicellular organisms. It is responsible for expelling excess water from the cell, helping to maintain osmotic balance. This is crucial for organisms living in freshwater environments.</div>", "topic": "CELL STRUCTURE AND FUNCTIONS"}, {"id": "objective>Biology>1992>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following insects undergoes incomplete metamorphosis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Termite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Housefly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Moth</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The termite undergoes incomplete metamorphosis, which is characterized by three life stages: egg, nymph, and adult. Unlike complete metamorphosis, there is no distinct larval stage. The nymphs resemble smaller versions of the adults and gradually develop into adults through a series of molts.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : INSECTA"}, {"id": "objective>Biology>1992>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An onion is a bulb because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">has a tuberous stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a reduced stem and thick fleshy leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has adventitous roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bears many buds at the nodes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An onion is classified as a bulb because it has a reduced stem and thick fleshy leaves. Bulbs are storage organs that allow the plant to survive adverse conditions and regrow in favorable conditions. The fleshy leaves store nutrients and water, which are essential for the plant's growth.</div>", "topic": "CLASSIFICATION OF PLANTS"}, {"id": "objective>Biology>1992>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The flow of air and water in or out of the mesophyll layer of a leaf is controlled by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lenticels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air space</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guard cell</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The flow of air and water in or out of the mesophyll layer of a leaf is controlled by the guard cells. Guard cells are specialized cells that surround the stomata (pores) and regulate their opening and closing, thus controlling gas exchange and transpiration in the leaf.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1992>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi are heterotropic because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have no leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are filamentous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack chlorophyll</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi are heterotrophic because they lack chlorophyll, which means they cannot perform photosynthesis. Instead, they obtain their nutrients by absorbing organic matter from their environment, making them dependent on other organisms for food.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>1992>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major site of photosynthesis in the leaf is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">palisade parenchyma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mesophyll parenchyma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upper epidermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower epidermis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major site of photosynthesis in the leaf is the palisade parenchyma. This tissue is located just beneath the upper epidermis and contains a high density of chloroplasts, which are essential for capturing light energy and converting it into chemical energy during photosynthesis.</div>", "topic": "PHOTOSYNTHESIS"}, {"id": "objective>Biology>1992>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">5 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> dilute sodium hydroxide solution and 5 cm3 one percent copper sulphate solution are added to a solution of food specimen. The purple colour which is observed shows the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protein</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purple color observed when dilute sodium hydroxide solution and copper sulfate solution are added to a food specimen indicates the presence of protein. This is a result of the biuret test, where proteins react with copper ions in an alkaline solution to produce a purple color.</div>", "topic": "NUTRITION : TYPES OF NUTRITION"}, {"id": "objective>Biology>1992>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The blood vessel which carries blood from the alimentary canal to the liver is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hepatic artery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hepatic vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hepatic portal vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mesenteric artery</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The blood vessel that carries blood from the alimentary canal to the liver is the hepatic portal vein. This vein transports nutrient-rich blood from the gastrointestinal tract and spleen to the liver for processing before it enters the general circulation.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1992>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gaseous exchange in Aves occurs in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tracheoles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bronchi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air sacs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gaseous exchange in Aves (birds) occurs in air sacs, which are part of their unique respiratory system. Unlike mammals, birds have a highly efficient system that includes air sacs that allow for a continuous flow of air through the lungs, facilitating gas exchange during both inhalation and exhalation.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>1992>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the absence of oxygen, the pyruvic acid produced during glycolysis is converted to CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glycerol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">citric acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the absence of oxygen, the pyruvic acid produced during glycolysis is converted to ethanol through a process called alcoholic fermentation. This occurs in yeast and some bacteria, where pyruvic acid is first converted to acetaldehyde and then to ethanol, releasing carbon dioxide in the process.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION~~RESPIRATION : ANAEROBIC RESPIRATION"}, {"id": "objective>Biology>1992>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excretory organ in insects is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kidney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">malpighian tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flame cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nephridium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excretory organ in insects is the malpighian tubule. These structures are responsible for the removal of waste products from the hemolymph (insect blood) and play a crucial role in osmoregulation.</div>", "topic": "EXCRETION : TYPES OF EXCRETORY STRUCTURES"}, {"id": "objective>Biology>1992>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled 5 is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sweat gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sebaceous gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood vessel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nerve fibre</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sweat glands, also known as sudoriferous glands, are categorized into two main types: eccrine and apocrine. Eccrine glands are distributed across the body, with high concentrations on the palms and soles, and they open directly onto the skin surface. Apocrine glands are primarily located in areas like the axilla and groin, and they open into hair follicles. Both types consist of secretory cells and a central lumen where sweat is secreted. </div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1992>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Melanin and keratin are produced in the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Melanin and keratin are both produced in the stratum basale, the deepest layer of the epidermis. Specifically, melanocytes, a type of cell found in the stratum basale, produce melanin, while the keratinocytes (also located in the stratum basale) produce keratin. </div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>1992>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bone of the neck on which the skull rests is known as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">odontoid process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">axis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">atlas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occipital condyle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bone of the neck on which the skull rests is known as the atlas. The atlas is the first cervical vertebra and supports the globe of the head, allowing for the nodding motion of the skull.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1992>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which enzymes are contained in the pancreatic juice?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ptayalin, lipase and pepsin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maltase, erepsin and trypsin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Renin, sucrase and lipase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amylase, lipase and trypsin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzymes contained in pancreatic juice include amylase, lipase, and trypsin. Amylase helps in the digestion of carbohydrates, lipase is responsible for fat digestion, and trypsin aids in protein digestion. These enzymes are crucial for the digestive process in the small intestine.</div>", "topic": "DIGESTIVE SYSTEM"}, {"id": "objective>Biology>1992>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled 3 is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cartilage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ligament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synovial fluid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bone</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Synovial fluid is the thick, slippery fluid found inside the cavities of synovial joints (like the knee, elbow, shoulder, hip).</div>", "topic": "N/A"}, {"id": "objective>Biology>1992>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the part labelled 1 is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">secrete a fluid which lubricates the joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attach muscles to the bones at the joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bend the bones at the joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hold the joint in place</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the part labelled 1 is to secrete a fluid which lubricates the joint. This fluid, known as synovial fluid, reduces friction between the articular cartilages of synovial joints during movement.</div>", "topic": "N/A"}, {"id": "objective>Biology>1992>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Double fertilization in higher plants is significant because it ensures the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">formation of a fertile embryo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of a fertile embryo and the endosperm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">developement of the seed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">developement of the fruit</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Double fertilization in higher plants is significant because it ensures the formation of a fertile embryo and the endosperm. This process involves one sperm fertilizing the egg cell to form the embryo, while another sperm fuses with two polar nuclei to form the triploid endosperm, which provides nourishment to the developing embryo.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>1992>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In mammalian development, the function of the yolk is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply nutrients to the embryo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">act as the shock-absorber to the foetus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply air to the embryo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitates the process of excretion in the foetus</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In mammalian development, the yolk primarily serves to supply nutrients to the developing embryo. This is crucial for the growth and development of the embryo, especially in species where the embryo relies on the yolk for sustenance during early stages of development.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>1992>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hypogeal germination is characterized by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emergency of the plumule out of the ground</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of nourishment by the endosperm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elongation of the hypocotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elongation of the epicotyl</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hypogeal germination is characterized by the elongation of the epicotyl, which allows the cotyledons to remain below the soil surface while the shoot grows upwards. This type of germination is common in certain plants, such as beans.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>1992>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fruits which develop without fertilization of the ovule are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">false</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aggregate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parthenocarpic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fruits that develop without fertilization of the ovule are termed parthenocarpic. This means that the fruit can develop without the need for fertilization, resulting in seedless fruits, which is common in certain cultivated varieties.</div>", "topic": "FRUITS"}, {"id": "objective>Biology>1992>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which part of the curve represents the fastest rate of growth?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the growth curve of microorganisms, the fastest growth occurs in the log or exponential phase, which follows the lag phase and precedes the stationary and death phases.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>1992>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The grand period of growth is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Grand period of growth is characterised by a \"rapid growth\". 'M' in the sigmoid curve represented the log or exponential phase where growth is rapid and the 'N' represented the lag phase where growth is slow.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>1992>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Neurons that receive stimuli from the body or internal organs are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sensory neurons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efferent neurones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motor neurones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relay neurones</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neurons that receive stimuli from the body or internal organs are called sensory neurons. These neurons are responsible for transmitting sensory information from the peripheral body parts to the central nervous system.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1992>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true of climax community?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it persists until the enviroment or climate changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it changes drastically from one year to the next</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is first stage in succession</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is made up of the tallest trees and the smallest</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A climax community is a stable and mature ecological community that undergoes little change in species composition. It persists until there is a significant change in the environment or climate, which can lead to a new ecological succession.</div>", "topic": "ECOLOGY"}, {"id": "objective>Biology>1992>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A population is defined as a collection of similar organism that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">behave in the same way</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interbreed freely</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are found in the same habitat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eat the same food</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A population is defined as a collection of similar organisms that interbreed freely. This definition emphasizes the reproductive aspect of a population, distinguishing it from other groups of organisms.</div>", "topic": "ECOLOGY : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>1992>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In typical predator food chain involving secondary and tertiary consumers, the organism become progressively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">smaller and more numerous along the food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal in number and size along the food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">larger and fewer along the food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitized along the food chain as consumers get bigger</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a typical predator food chain, organisms become progressively larger and fewer as you move from primary consumers to secondary and tertiary consumers. This is due to the energy loss at each trophic level, which results in fewer individuals being supported at higher levels.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1992>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which level of the pyramid has the least total stored energy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shark's position – Since the shark is at the top (Level H), it receives energy that has already been transferred and reduced through several stages (producers → primary consumers → secondary consumers → tertiary consumers).</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>1992>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which organism in the pyramid functions as a tertiary consumer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Algae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tadpole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tilapia</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain, tertiary consumers are organisms that eat secondary consumers. In this case, a shark is a tertiary consumer as it preys on smaller fish (secondary consumers) and is at the top of the food chain in aquatic ecosystems.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1992>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mangrove swamp can be found</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">on a seashore with flat terrains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">where a river meets the sea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on a mud flat near the sea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">where two rivers meet</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mangrove swamps are typically found where freshwater from rivers meets saltwater from the sea, creating a unique ecosystem that supports mangrove trees. This is known as an estuarine environment.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST"}, {"id": "objective>Biology>1992>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil with the finest particles is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gravel</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil with the finest particles is called clay. Clay particles are smaller than silt and sand, which gives clay its unique properties, such as high plasticity and the ability to retain water.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>1992>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Malaria symptoms are caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">toxins released into the blood as a result of the destruction of red blood cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the multiplications of the malaria sporozites in the liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the invasion of the red blood cells by the trophozoites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the development of merozoites into gametocytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Malaria symptoms are primarily caused by the invasion of red blood cells by the trophozoites, which are the active feeding stage of the malaria parasite. This leads to the destruction of red blood cells and the associated symptoms of malaria.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1992>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true of the children of a heamophilic man who marries a woman that is not haemophilic and does not carry the trait?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">All their sons will be haemophlic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all their daughters will be haemophilic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all their daughters will be carriers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all their sons will be carriers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hemophilic man has the hemophilia trait on his X chromosome. Since he marries a woman who is not hemophilic and does not carry the trait, all their daughters will inherit one X chromosome from their father (the hemophilic one) and one from their mother (normal), making them carriers of the hemophilia trait, but not affected by it.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>1992>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A child with blood group genotype different from those of both parents and with a mother of genotype OO, can only have a father of genotype</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OO</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A child with blood group genotype different from both parents indicates that the father must have a genotype that can contribute an allele not present in the mother. Since the mother has genotype OO, she can only contribute an O allele. Therefore, the father must have at least one A or B allele to produce a child with blood group A (genotype AO) or B (genotype BO). The only option that allows for this is AB, which can provide both A and B alleles.</div>", "topic": "HEREDITY : BLOOD GROUPS"}, {"id": "objective>Biology>1992>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If R and r, denotes the genes for a character, the offspring of the cross between RR and Rr are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">RR, 2Rr, rr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2RR, 2rr, 2rr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2RR, 2Rr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4Rr</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a cross between RR (homozygous dominant) and Rr (heterozygous), the possible genotypes of the offspring are RR and Rr. The Punnett square for this cross shows that there are 2 RR and 2 Rr offspring, leading to the conclusion that the offspring will be 2RR and 2Rr.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1992>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mammal with red fur and long ears was crossed with another having white fur and short ears. If the offspring had a red fur and short ears, the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">character are linked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">character are not linked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parents are related</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parents are not related</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The offspring having red fur and short ears suggests that the traits for fur color and ear length are not linked. If they were linked, we would expect to see a consistent combination of traits in the offspring. The presence of red fur (dominant) and short ears (also likely dominant) indicates independent assortment of these traits.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1992>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pawpaw seeds collected from a tree with many desirable agronomic qualities did not give rise to plants of desirable character as the parent because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seeds are not reliable for propagating plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uncontrolled out-crossing can introduced unwanted variability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetative propagation is best form of reproduction of all crop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seeds were not physiologically mature at the harvest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pawpaw seeds may not give rise to desirable plants due to uncontrolled out-crossing, which can introduce unwanted genetic variability. This means that even if the parent plant has desirable traits, the seeds may inherit traits from other plants, leading to variability in the offspring.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>1992>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Woman do not suffer from colour blindness because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the trait is sex-linked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only men are colour blind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the genes are recessive and sex-linked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the genes occur on both the X and Y chromosomes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Color blindness is a sex-linked trait, primarily located on the X chromosome. Women have two X chromosomes, so they can be carriers without expressing the trait if they have one normal allele. Men, having only one X chromosome, will express color blindness if they inherit the recessive allele. Therefore, women do not suffer from color blindness as frequently as men because they have two X chromosomes, which provides a backup for the normal allele.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>1992>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hereditary materials of the cell is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the RNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the DNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbohydrate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hereditary material of the cell is DNA (deoxyribonucleic acid). DNA carries the genetic instructions used in the growth, development, functioning, and reproduction of all known living organisms and many viruses. It is the primary component of chromosomes, which are found in the nucleus of eukaryotic cells.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1992>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of plant adaptation to a xerophytic environment is represented by the development of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fleshy tissue and reduced leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">broad canopy and extensive surface root system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thick barks and broad leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rough leaves and shallow root system</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An example of plant adaptation to a xerophytic environment is the development of fleshy tissue and reduced leaves. Xerophytes are plants adapted to survive in environments with very little water, and they often have adaptations such as thick, fleshy tissues to store water and reduced leaf surface area to minimize water loss through transpiration.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1992>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors is LEAST likely to affect the animals living in a fresh water habitat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Turbidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Salinity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Salinity is the factor least likely to affect animals living in a freshwater habitat. Freshwater habitats typically have low salinity levels, and while turbidity, temperature, and pH can significantly impact aquatic life, salinity is not a relevant factor in freshwater environments as it is in marine environments.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1992>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of natural selection was developed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lamarck and Darwin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Darwin and Wallace</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wallace and Mendel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mendel and Larmack</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of natural selection was developed by Charles Darwin and Alfred Russel Wallace. They independently formulated the concept that species evolve over time through a process of natural selection, where individuals with advantageous traits are more likely to survive and reproduce.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>1992>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fossil records found in sedimentary rocks offer some explanation for the theory of evolution because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the deposit have remains of organisms characteristic of when they were formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different strata have remains of organisms of the same kind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only organisms with strong parts are fossilized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">most animal and plant fossils bear little resemblance to present day living specimens</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fossil records found in sedimentary rocks support the theory of evolution because these deposits contain remains of organisms that are characteristic of the time period in which they were formed. This provides evidence of how life has changed over geological time, showing a progression of species and adaptations.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}];
